from flask import Flask, render_template, redirect, url_for, request
import os
from datetime import datetime

app = Flask(__name__)
app.config['SECRET_KEY'] = 'dev-secret-key'

DATA_DIR = os.path.join(os.path.dirname(__file__), 'data')

# Helper functions to load data

def load_users():
    users = {}
    path = os.path.join(DATA_DIR, 'users.txt')
    if os.path.exists(path):
        with open(path, 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 4:
                    username, email, phone, full_name = parts
                    users[username] = {
                        'username': username,
                        'email': email,
                        'phone': phone,
                        'full_name': full_name
                    }
    return users


def load_menu():
    menu = []
    path = os.path.join(DATA_DIR, 'menu.txt')
    if os.path.exists(path):
        with open(path, 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 8:
                    dish_id = int(parts[0])
                    name = parts[1]
                    category = parts[2]
                    try:
                        price = float(parts[3])
                    except ValueError:
                        price = 0.0
                    description = parts[4]
                    ingredients = parts[5]
                    dietary = parts[6]
                    try:
                        avg_rating = float(parts[7])
                    except ValueError:
                        avg_rating = 0.0
                    menu.append({
                        'dish_id': dish_id,
                        'name': name,
                        'category': category,
                        'price': price,
                        'description': description,
                        'ingredients': ingredients,
                        'dietary': dietary,
                        'avg_rating': avg_rating
                    })
    return menu


def load_reservations():
    reservations = []
    path = os.path.join(DATA_DIR, 'reservations.txt')
    if os.path.exists(path):
        with open(path, 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 10:
                    try:
                        reservation_id = int(parts[0])
                        username = parts[1]
                        guest_name = parts[2]
                        phone = parts[3]
                        email = parts[4]
                        party_size = int(parts[5])
                        date = parts[6]
                        time = parts[7]
                        special_requests = parts[8]
                        status = parts[9]
                        reservations.append({
                            'reservation_id': reservation_id,
                            'username': username,
                            'guest_name': guest_name,
                            'phone': phone,
                            'email': email,
                            'party_size': party_size,
                            'date': date,
                            'time': time,
                            'special_requests': special_requests,
                            'status': status
                        })
                    except ValueError:
                        continue
    return reservations


def load_waitlist():
    waitlist = []
    path = os.path.join(DATA_DIR, 'waitlist.txt')
    if os.path.exists(path):
        with open(path, 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 5:
                    try:
                        waitlist_id = int(parts[0])
                        username = parts[1]
                        party_size = int(parts[2])
                        join_time = parts[3]
                        status = parts[4]
                        waitlist.append({
                            'waitlist_id': waitlist_id,
                            'username': username,
                            'party_size': party_size,
                            'join_time': join_time,
                            'status': status
                        })
                    except ValueError:
                        continue
    return waitlist


def load_reviews():
    reviews = []
    path = os.path.join(DATA_DIR, 'reviews.txt')
    if os.path.exists(path):
        with open(path, 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 6:
                    try:
                        review_id = int(parts[0])
                        username = parts[1]
                        dish_id = int(parts[2])
                        rating = int(parts[3])
                        review_text = parts[4]
                        review_date = parts[5]
                        reviews.append({
                            'review_id': review_id,
                            'username': username,
                            'dish_id': dish_id,
                            'rating': rating,
                            'review_text': review_text,
                            'review_date': review_date
                        })
                    except ValueError:
                        continue
    return reviews

# Helper function to save reservations

def save_reservations(reservations):
    path = os.path.join(DATA_DIR, 'reservations.txt')
    with open(path, 'w', encoding='utf-8') as f:
        for r in reservations:
            line = f"{r['reservation_id']}|{r['username']}|{r['guest_name']}|{r['phone']}|{r['email']}|{r['party_size']}|{r['date']}|{r['time']}|{r['special_requests']}|{r['status']}\n"
            f.write(line)


# Helper function to save waitlist

def save_waitlist(waitlist):
    path = os.path.join(DATA_DIR, 'waitlist.txt')
    with open(path, 'w', encoding='utf-8') as f:
        for w in waitlist:
            line = f"{w['waitlist_id']}|{w['username']}|{w['party_size']}|{w['join_time']}|{w['status']}\n"
            f.write(line)

# Helper function to save reviews

def save_reviews(reviews):
    path = os.path.join(DATA_DIR, 'reviews.txt')
    with open(path, 'w', encoding='utf-8') as f:
        for r in reviews:
            line = f"{r['review_id']}|{r['username']}|{r['dish_id']}|{r['rating']}|{r['review_text']}|{r['review_date']}\n"
            f.write(line)

# Helper function to save users

def save_users(users):
    path = os.path.join(DATA_DIR, 'users.txt')
    with open(path, 'w', encoding='utf-8') as f:
        for u in users.values():
            line = f"{u['username']}|{u['email']}|{u['phone']}|{u['full_name']}\n"
            f.write(line)


# Dummy current user
# For this implementation, assume logged in user is 'john_diner'
CURRENT_USER = 'john_diner'


@app.route('/')
def root_redirect():
    return redirect(url_for('dashboard'))


@app.route('/dashboard')
def dashboard():
    username = CURRENT_USER
    menu = load_menu()

    # Featured dishes - choose top 3 dishes by avg_rating descending
    sorted_menu = sorted(menu, key=lambda d: d['avg_rating'], reverse=True)
    featured_dishes = [{'dish_id': d['dish_id'], 'name': d['name'], 'price': d['price']} for d in sorted_menu[:3]]

    # Load reservations for current user and filter upcoming
    reservations = load_reservations()
    upcoming_reservations = [
        {
            'reservation_id': r['reservation_id'],
            'date': r['date'],
            'time': r['time'],
            'party_size': r['party_size'],
            'status': r['status']
        }
        for r in reservations if r['username'] == username and r['status'] == 'Upcoming'
    ]

    return render_template('dashboard.html', username=username, featured_dishes=featured_dishes, upcoming_reservations=upcoming_reservations)


@app.route('/menu')
def menu():
    menu = load_menu()
    # Context menu: list of dict {dish_id:int, name:str, category:str, price:float, description:str}
    menu_context = [
        {
            'dish_id': item['dish_id'],
            'name': item['name'],
            'category': item['category'],
            'price': item['price'],
            'description': item['description']
        } for item in menu
    ]
    return render_template('menu.html', menu=menu_context)


@app.route('/dish/<int:dish_id>')
def dish_details(dish_id):
    menu = load_menu()
    dish = None
    for item in menu:
        if item['dish_id'] == dish_id:
            dish = {
                'dish_id': item['dish_id'],
                'name': item['name'],
                'price': item['price'],
                'description': item['description']
            }
            break
    if dish is None:
        # Dish not found, redirect to menu
        return redirect(url_for('menu'))
    return render_template('dish_details.html', dish=dish)


@app.route('/make_reservation', methods=['GET', 'POST'])
def make_reservation():
    if request.method == 'GET':
        # Render the reservation form
        return render_template('make_reservation.html')

    # POST: process reservation form
    guest_name = request.form.get('guest_name', '').strip()
    try:
        party_size = int(request.form.get('party_size', '1'))
    except ValueError:
        party_size = 1
    reservation_date = request.form.get('reservation_date', '').strip()

    # Validate party size
    if party_size < 1 or party_size > 10:
        party_size = 1

    # Validate reservation_date (simple check YYYY-MM-DD)
    try:
        datetime.strptime(reservation_date, '%Y-%m-%d')
    except ValueError:
        # Invalid date - redirect back to make_reservation GET
        return redirect(url_for('make_reservation'))

    # Load current users to get contact info
    users = load_users()
    user = users.get(CURRENT_USER)
    if not user:
        # No user data, error fallback
        return redirect(url_for('make_reservation'))

    # Compose new reservation
    reservations = load_reservations()
    if reservations:
        new_id = max(r['reservation_id'] for r in reservations) + 1
    else:
        new_id = 1

    # Use current time for reservation time - for demo use fixed time 19:00
    reservation_time = '19:00'

    new_reservation = {
        'reservation_id': new_id,
        'username': CURRENT_USER,
        'guest_name': guest_name if guest_name else user['full_name'],
        'phone': user['phone'],
        'email': user['email'],
        'party_size': party_size,
        'date': reservation_date,
        'time': reservation_time,
        'special_requests': '',
        'status': 'Upcoming'
    }

    reservations.append(new_reservation)
    save_reservations(reservations)

    return redirect(url_for('my_reservations'))


@app.route('/my_reservations')
def my_reservations():
    reservations = load_reservations()
    user_reservations = [
        {
            'reservation_id': r['reservation_id'],
            'date': r['date'],
            'time': r['time'],
            'party_size': r['party_size'],
            'status': r['status']
        }
        for r in reservations if r['username'] == CURRENT_USER
    ]
    return render_template('my_reservations.html', reservations=user_reservations)


@app.route('/cancel_reservation/<int:reservation_id>', methods=['POST'])
def cancel_reservation(reservation_id):
    reservations = load_reservations()
    changed = False
    for r in reservations:
        if r['reservation_id'] == reservation_id and r['username'] == CURRENT_USER and r['status'] == 'Upcoming':
            r['status'] = 'Cancelled'
            changed = True
            break
    if changed:
        save_reservations(reservations)
    return redirect(url_for('my_reservations'))


@app.route('/waitlist', methods=['GET', 'POST'])
def waitlist():
    waitlist = load_waitlist()

    # Find if current user is active in waitlist
    position = None
    if request.method == 'GET':
        # Calculate position if user in active waitlist
        active_entries = [w for w in waitlist if w['status'] == 'Active']
        # sort by join_time ascending
        active_entries.sort(key=lambda x: x['join_time'])
        for idx, entry in enumerate(active_entries, 1):
            if entry['username'] == CURRENT_USER:
                position = idx
                break

        return render_template('waitlist.html', position=position)
    else:
        # POST: join waitlist
        try:
            party_size = int(request.form.get('party_size', '1'))
        except ValueError:
            party_size = 1

        if party_size < 1:
            party_size = 1

        # Check if user already active in waitlist
        for w in waitlist:
            if w['username'] == CURRENT_USER and w['status'] == 'Active':
                # Already on waitlist, just render current position
                active_entries = [w for w in waitlist if w['status'] == 'Active']
                active_entries.sort(key=lambda x: x['join_time'])
                position = None
                for idx, entry in enumerate(active_entries, 1):
                    if entry['username'] == CURRENT_USER:
                        position = idx
                        break
                return render_template('waitlist.html', position=position)

        # Add new waitlist entry
        if waitlist:
            new_id = max(w['waitlist_id'] for w in waitlist) + 1
        else:
            new_id = 1
        now_ts = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        waitlist.append({
            'waitlist_id': new_id,
            'username': CURRENT_USER,
            'party_size': party_size,
            'join_time': now_ts,
            'status': 'Active'
        })
        save_waitlist(waitlist)

        # After joining, recalc position
        active_entries = [w for w in waitlist if w['status'] == 'Active']
        active_entries.sort(key=lambda x: x['join_time'])
        position = None
        for idx, entry in enumerate(active_entries, 1):
            if entry['username'] == CURRENT_USER:
                position = idx
                break
        return render_template('waitlist.html', position=position)


@app.route('/my_reviews')
def my_reviews():
    reviews = load_reviews()
    menu = load_menu()
    # Get reviews by current user
    user_reviews = []
    dish_dict = {d['dish_id']: d['name'] for d in menu}
    for r in reviews:
        if r['username'] == CURRENT_USER:
            dish_name = dish_dict.get(r['dish_id'], 'Unknown')
            user_reviews.append({
                'review_id': r['review_id'],
                'dish_name': dish_name,
                'rating': r['rating'],
                'review_text': r['review_text']
            })
    return render_template('my_reviews.html', reviews=user_reviews)


@app.route('/write_review', methods=['GET', 'POST'])
def write_review():
    menu = load_menu()
    dishes = [{'dish_id': d['dish_id'], 'name': d['name']} for d in menu]

    if request.method == 'GET':
        return render_template('write_review.html', dishes=dishes)

    dish_id_raw = request.form.get('dish_id', '')
    rating_raw = request.form.get('rating', '')
    review_text = request.form.get('review_text', '').strip()

    try:
        dish_id = int(dish_id_raw)
        rating = int(rating_raw)
    except ValueError:
        return redirect(url_for('write_review'))

    if rating < 1 or rating > 5:
        return redirect(url_for('write_review'))

    reviews = load_reviews()
    if reviews:
        new_id = max(r['review_id'] for r in reviews) + 1
    else:
        new_id = 1

    now_date = datetime.now().strftime('%Y-%m-%d')

    new_review = {
        'review_id': new_id,
        'username': CURRENT_USER,
        'dish_id': dish_id,
        'rating': rating,
        'review_text': review_text,
        'review_date': now_date
    }

    reviews.append(new_review)
    save_reviews(reviews)

    return redirect(url_for('my_reviews'))


@app.route('/profile', methods=['GET', 'POST'])
def profile():
    users = load_users()
    user = users.get(CURRENT_USER)
    if not user:
        # If user not found in users.txt, create a default one for display
        user = {'username': CURRENT_USER, 'email': '', 'phone': '', 'full_name': ''}

    if request.method == 'GET':
        return render_template('profile.html', user={'username': user['username'], 'email': user['email']})

    # POST: update email
    email = request.form.get('email', '').strip()
    if email:
        user['email'] = email
        users[CURRENT_USER] = user
        save_users(users)

    return redirect(url_for('profile'))


if __name__ == '__main__':
    app.run(debug=True)


