            <label for="dish-select">Dish:</label>
            <select id="dish-select" name="dish_id" required>
                {% for dish in dishes %}
                <option value="{{ dish.dish_id }}">{{ dish.name }}</option>
                {% endfor %}
            </select>

            <label for="rating-input">Rating (1-5):</label>
            <input type="number" id="rating-input" name="rating" min="1" max="5" required>

            <label for="review-text">Review:</label>
            <textarea id="review-text" name="review_text" required></textarea>

            <button type="submit">Submit</button>
        </form>
        <button id="back-to-my-reviews" onclick="window.location.href='{{ url_for('my_reviews') }}'">Back to My Reviews</button>
    </div>
</body>
</html>

